        "id": 25,
        "name": "Acordeón",
        "category": "Componentes UI",
        "description": "Sección colapsable ideal para FAQs donde solo se muestra el texto al hacer clic.",
        "html": "<div class=\"accordion\" data-accordion>\n    <button class=\"accordion__button\">¿Para qué sirve?</button>\n    <div class=\"accordion__content\">Para reutilizar código.</div>\n</div>",
        "css": ".accordion {\n    max-width: 520px;\n}\n.accordion__button {\n    width: 100%;\n    padding: 12px 14px;\n    border: 1px solid #cbd5e1;\n    border-radius: 12px;\n    background: #ffffff;\n    text-align: left;\n    cursor: pointer;\n}\n.accordion__content {\n    max-height: 0;\n    overflow: hidden;\n    margin-top: 8px;\n    border-radius: 12px;\n    background: #f8fafc;\n    transition: max-height 0.2s ease, padding 0.2s ease;\n}\n.accordion__content.is-open {\n    max-height: 140px;\n    padding: 12px;\n}",
        "jsModular": "const $ = (selector, parent = document) => parent.querySelector(selector);\nconst $$ = (selector, parent = document) => [...parent.querySelectorAll(selector)];\n\nexport class Accordion {\n    constructor(selector = \"[data-accordion]\") {\n        this.components = $$(selector);\n        this.init();\n    }\n\n    init() {\n        this.components.forEach((accordion) => {\n            const buttons = $$(\".accordion__button\", accordion);\n            buttons.forEach((button) => {\n                button.addEventListener(\"click\", () => button.nextElementSibling.classList.toggle(\"is-open\"));\n            });\n        });\n    }\n}\n\ndocument.addEventListener(\"DOMContentLoaded\", () => {\n    new Accordion();\n});",
        "jsNormal": "const $ = (selector, parent = document) => parent.querySelector(selector);\nconst $$ = (selector, parent = document) => [...parent.querySelectorAll(selector)];\n\nclass Accordion {\n    constructor(selector = \"[data-accordion]\") {\n        this.components = $$(selector);\n        this.init();\n    }\n\n    init() {\n        this.components.forEach((accordion) => {\n            const buttons = $$(\".accordion__button\", accordion);\n            buttons.forEach((button) => {\n                button.addEventListener(\"click\", () => button.nextElementSibling.classList.toggle(\"is-open\"));\n            });\n        });\n    }\n}\n\ndocument.addEventListener(\"DOMContentLoaded\", () => {\n    new Accordion();\n});"
