        "description": "Pequeñas alertas tipo toast o badges de cambio de estado tras guardar o eliminar.",
        "html": "<button id=\"saveVisualState\" type=\"button\">Guardar cambio</button>\n<div id=\"toastContainer\"></div>",
        "css": "#toastContainer {\n    position: fixed;\n    right: 20px;\n    bottom: 20px;\n    display: grid;\n    gap: 10px;\n}\n.toast {\n    padding: 12px 14px;\n    border-radius: 12px;\n    background: #0f172a;\n    color: #ffffff;\n}",
        "jsModular": "class ToastManager {\n    constructor(containerId = \"toastContainer\") {\n        this.container = document.getElementById(containerId);\n    }\n\n    show(message, time = 2800) {\n        const toast = document.createElement(\"div\");\n        toast.className = \"toast\";\n        toast.textContent = message;\n        this.container.appendChild(toast);\n        setTimeout(() => toast.remove(), time);\n    }\n}\n\ndocument.addEventListener(\"DOMContentLoaded\", () => {\n    const toast = new ToastManager();\n    document.getElementById(\"saveVisualState\")?.addEventListener(\"click\", () => {\n        toast.show(\"Cambio guardado correctamente.\");\n    });\n});",
        "jsNormal": "class ToastManager {\n    constructor(containerId = \"toastContainer\") {\n        this.container = document.getElementById(containerId);\n    }\n\n    show(message, time = 2800) {\n        const toast = document.createElement(\"div\");\n        toast.className = \"toast\";\n        toast.textContent = message;\n        this.container.appendChild(toast);\n        setTimeout(() => toast.remove(), time);\n    }\n}\n\ndocument.addEventListener(\"DOMContentLoaded\", () => {\n    const toast = new ToastManager();\n    document.getElementById(\"saveVisualState\")?.addEventListener(\"click\", () => {\n        toast.show(\"Cambio guardado correctamente.\");\n    });\n});"
